from flask import Flask, request, jsonify
import json
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(url, params):
    return f"{url}_{hash(tuple(sorted(params.items())))}"

def load_cache(key):
    file_path = os.path.join(CACHE_DIR, key)
    if os.path.exists(file_path) and time.time() - os.path.getmtime(file_path) <= 3600:  # Cache expires after 1 hour
        with open(file_path, 'r') as f:
            return json.load(f)
    return None

def save_cache(key, data):
    file_path = os.path.join(CACHE_DIR, key)
    with open(file_path, 'w') as f:
        json.dump(data, f)

@app.route('/api', methods=['GET'])
def api():
    url = request.url
    params = request.args.to_dict()
    cache_key_value = cache_key(url, params)
    
    cached_data = load_cache(cache_key_value)
    if cached_data is not None:
        return jsonify(cached_data), 200
    
    # Simulate an expensive API call
    response_data = {
        'data': [
            {'id': 1, 'name': 'Item 1'},
            {'id': 2, 'name': 'Item 2'}
        ],
        'metadata': {
            'timestamp': time.time()
        }
    }
    
    save_cache(cache_key_value, response_data)
    return jsonify(response_data), 200

if __name__ == '__main__':
    app.run(debug=True)